package com.gz.tobacco.service.impl;

import cn.hutool.json.JSONUtil;
import com.gz.tobacco.auth.UserContext;
import com.gz.tobacco.classes.request.TopicSaveParam;
import com.gz.tobacco.classes.response.ChatMessage;
import com.gz.tobacco.feign.GptFeign;
import lombok.extern.slf4j.Slf4j;
import org.springframework.ai.chat.memory.ChatMemory;
import org.springframework.ai.chat.messages.AssistantMessage;
import org.springframework.ai.chat.messages.Message;
import org.springframework.ai.chat.messages.UserMessage;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;

import java.util.Collections;
import java.util.Comparator;
import java.util.List;
import java.util.Optional;
import java.util.stream.Collectors;
import java.util.stream.Stream;

@Slf4j
@Service
public class ChatMemoryService implements ChatMemory {

    @Autowired
    GptFeign gptFeign;

    @Override
    public void add(String conversationId, List<Message> messages) {
        // 提前检查参数，避免不必要的处理
        if (conversationId.isBlank() || messages == null || messages.isEmpty()) {
            return;
        }
        // 使用模式匹配 instanceof (JDK 17 特性)
        if (messages.get(0) instanceof UserMessage) {
            return;
        }
        TopicSaveParam param = JSONUtil.toBean(conversationId, TopicSaveParam.class);
        param.setAnswer(messages.get(0).getText());
        try {
            UserContext.setUser(param.getUserid(), param.getTokenType());
            param.setUserid("0");
            this.gptFeign.saveTopic(param);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
        //log.warn("保存聊天记录：{}", JSONUtil.toJsonStr(param));
    }

    @Override
    public List<Message> get(String conversationId) {
        TopicSaveParam param = JSONUtil.toBean(conversationId, TopicSaveParam.class);
        UserContext.setUser(param.getUserid(), param.getTokenType());
        List<ChatMessage> chatMessages = this.gptFeign.feignTopicItemsItem(param.getTopicid(), param.getItemid(), 1, 3);
        log.info("对话历史记录："+chatMessages.toString());
        return Optional.ofNullable(chatMessages)
            .orElse(Collections.emptyList())
            .stream()
            .sorted(Comparator.comparing(ChatMessage::getTime))
            .flatMap(chatMessage -> Stream.of(
                new UserMessage(chatMessage.getQuestion()),
                new AssistantMessage(chatMessage.getAnswer())
            ))
            .map(message -> (Message) message)
            .collect(Collectors.toList());
    }

    /**
     * 清除历史消息
     * @param params
     */
    @Override
    public void clear(String params) {

    }
}
